func getenv(key, def string) string {
	v := strings.TrimSpace(os.Getenv(key))
	if v == "" {
		return def
	}
	return v
}

func main() {
	addr := getenv("GRPC_ADDR", ":50051")
	lis, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatalf("listen: %v", err)
	}

	st := &services{
		us: &userStore{users: map[string]*User{}},
		os: &orderStore{orders: map[string]*Order{}},
		ps: &paymentStore{payments: map[string]*Payment{}},
	}

	grpcServer := grpc.NewServer()

	RegisterUserServiceServer(grpcServer, &userService{s: st})
	RegisterOrderServiceServer(grpcServer, &orderService{s: st})
	RegisterPaymentServiceServer(grpcServer, &paymentService{s: st})

	reflection.Register(grpcServer)

	errCh := make(chan error, 1)
	go func() {
		log.Printf("gRPC server listening on %s", addr)
		errCh <- grpcServer.Serve(lis)
	}()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, os.Interrupt, syscall.SIGTERM)

	select {
	case sig := <-sigCh:
		log.Printf("signal: %v, shutting down", sig)
		grpcServer.GracefulStop()
	case err := <-errCh:
		log.Printf("server error: %v", err)
		grpcServer.Stop()
	}
}